var baseUrl = 'https://{$SMARTZONE_URL}/wsg/api/public/v6_1';
var cookie  = '{$SMARTZONE_TOKEN}';

function makeReq(c) {
    var req = new HttpRequest();
    req.addHeader('Content-Type: application/json;charset=UTF-8');
    if (c) req.addHeader('Cookie: ' + c);
    return req;
}

function login() {
    var user = '{$SMARTZONE_USER}';
    var pass = '{$SMARTZONE_PASS}';
    if (!user || !pass) return null;
    var req = makeReq(null);
    try {
        var resp = req.post(baseUrl + '/session', JSON.stringify({username: user, password: pass}));
        if (req.getStatus() === 200) {
            var body = JSON.parse(resp);
            if (body.sessionId) return 'JSESSIONID=' + body.sessionId;
        }
        Zabbix.log(3, 'SmartZone100: login failed: ' + req.getStatus());
    } catch (e) {
        Zabbix.log(3, 'SmartZone100: login error: ' + e.message);
    }
    return null;
}

// Fetch all domains recursively
var activeCookie = cookie;
var req = makeReq(activeCookie);
var resp = req.get(baseUrl + '/domains?recursively=true&listSize=1000');
if (req.getStatus() === 401 || req.getStatus() === 403) {
    Zabbix.log(4, 'SmartZone100: session expired, re-authenticating');
    activeCookie = login();
    if (!activeCookie) throw new Error('SmartZone100: auth failed');
    req = makeReq(activeCookie);
    resp = req.get(baseUrl + '/domains?recursively=true&listSize=1000');
}

var domList = [];
if (req.getStatus() === 200) {
    domList = JSON.parse(resp).list || [];
} else {
    // Fallback: no domain hierarchy, fetch flat zone list
    Zabbix.log(4, 'SmartZone100: /domains not available (' + req.getStatus() + '), using flat zone list');
    var zReq = makeReq(activeCookie);
    var zResp = zReq.get(baseUrl + '/rkszones?listSize=1000');
    if (zReq.getStatus() !== 200) throw new Error('Zone list failed: ' + zReq.getStatus());
    var zList = JSON.parse(zResp).list || [];
    var zones = [];
    for (var zi = 0; zi < zList.length; zi++) {
        var z = zList[zi];
        zones.push({zoneId: z.id, zoneName: z.name, domainId: null, zonePath: z.name});
    }
    return JSON.stringify(zones);
}

// Build domain map {id: {name, parent, zoneCount}}
var domMap = {};
for (var i = 0; i < domList.length; i++) {
    var d = domList[i];
    domMap[d.id] = {name: d.name, parent: d.parentDomainId || null, zoneCount: d.zoneCount || 0};
}

// Build hierarchy path: 'Domain :: Sub :: ...' (stops at root = no parent)
function domainPath(id) {
    var parts = [], cur = id, seen = {};
    while (cur && domMap[cur] && domMap[cur].parent && !seen[cur]) {
        seen[cur] = 1;
        parts.unshift(domMap[cur].name);
        cur = domMap[cur].parent;
    }
    return parts.join(' :: ');
}

// Fetch zones for each domain that has zones
var zones = [];
for (var domId in domMap) {
    if (!domMap[domId].zoneCount) continue;
    var zReq = makeReq(activeCookie);
    var zResp = zReq.get(baseUrl + '/rkszones?domainId=' + domId + '&listSize=1000');
    if (zReq.getStatus() !== 200) {
        Zabbix.log(4, 'SmartZone100: zones for domain ' + domId + ' failed: ' + zReq.getStatus());
        continue;
    }
    var dPath = domainPath(domId);
    var zList = JSON.parse(zResp).list || [];
    for (var j = 0; j < zList.length; j++) {
        var z = zList[j];
        zones.push({
            zoneId: z.id,
            zoneName: z.name,
            domainId: domId,
            zonePath: dPath ? dPath + ' :: ' + z.name : z.name
        });
    }
}

return JSON.stringify(zones);

var baseUrl  = 'https://{$SMARTZONE_URL}/wsg/api/public/v6_1';
var cookie   = '{$SMARTZONE_TOKEN}';
var zoneId   = '{$SMARTZONE_ZONE_ID}';
var listSize = 5;

function makeReq(c) {
    var req = new HttpRequest();
    req.addHeader('Content-Type: application/json;charset=UTF-8');
    if (c) req.addHeader('Cookie: ' + c);
    return req;
}

function login() {
    var user = '{$SMARTZONE_USER}';
    var pass = '{$SMARTZONE_PASS}';
    if (!user || !pass) return null;
    var req = makeReq(null);
    try {
        var resp = req.post(baseUrl + '/session', JSON.stringify({username: user, password: pass}));
        if (req.getStatus() === 200) {
            var body = JSON.parse(resp);
            if (body.sessionId) return 'JSESSIONID=' + body.sessionId;
        }
        Zabbix.log(3, 'SmartZone100: login failed: ' + req.getStatus());
    } catch (e) {
        Zabbix.log(3, 'SmartZone100: login error: ' + e.message);
    }
    return null;
}

// Fetch AP list for the configured zone
var activeCookie = cookie;
var listReq = makeReq(activeCookie);
var listResp = listReq.get(baseUrl + '/aps?zoneId=' + zoneId + '&listSize=' + listSize);
if (listReq.getStatus() === 401 || listReq.getStatus() === 403) {
    Zabbix.log(4, 'SmartZone100: session expired, re-authenticating');
    activeCookie = login();
    if (!activeCookie) throw new Error('SmartZone100: auth failed');
    listReq = makeReq(activeCookie);
    listResp = listReq.get(baseUrl + '/aps?zoneId=' + zoneId + '&listSize=' + listSize);
}
if (listReq.getStatus() !== 200) throw new Error('AP list failed: ' + listReq.getStatus());
var aps = JSON.parse(listResp).list || [];

// Enrich each AP with IP from operational summary
for (var i = 0; i < aps.length; i++) {
    var ap = aps[i];
    if (!ap.mac) { ap.ip = null; continue; }
    try {
        var sumReq = makeReq(activeCookie);
        var sumResp = sumReq.get(baseUrl + '/aps/' + ap.mac + '/operational/summary');
        if (sumReq.getStatus() === 200) {
            ap.ip = JSON.parse(sumResp).ip || null;
        } else {
            Zabbix.log(4, 'SmartZone100: summary mac=' + ap.mac + ' status=' + sumReq.getStatus());
            ap.ip = null;
        }
    } catch (e) {
        Zabbix.log(3, 'SmartZone100: summary error mac=' + ap.mac + ': ' + e.message);
        ap.ip = null;
    }
}

return JSON.stringify(aps);

